// Script Continued Below
closeAllRequestsOnCloseTasks();

function closeAllRequestsOnCloseTasks(){
	// ***************************************************************************
	// TO TEST COMMENTS SET TESTING TO TRUE
	// This is in just for testing, it could be removed, but hurts nothing as long as testing is set to false above
	// If removed, find everywhere the "testing" variable is used and delete or comment out
	// ***************************************************************************
	var testing = false;


	// count all open requests on closed tasks and log
	var ga = new GlideAggregate('x_153465_discovert_tasker_requests');
	ga.addEncodedQuery('u_status=In progress^parent.stateIN7,4,3');
	ga.addAggregate("COUNT");	
	ga.query();
	if(ga.next()){
		var requestNotClosedCount = ga.getAggregate("COUNT");
	}

	gs.info('Fix Script - Tasker 2.7-Close Requests on closed Task - Your system was analyzed and ' + requestNotClosedCount + ' requests with closed tasks are still in progress.  Closing the opened requests...');

	var numRequestsClosed = 0;
	// STRY0106180 - Find all open requests for the task and close them.
	var requests = new GlideRecord('x_153465_discovert_tasker_requests');
	requests.addEncodedQuery('u_status=In progress^parent.stateIN7,4,3');
	requests.query();
	while(requests.next()) {
		var taskNumberAndName;
		try
		{
			var grTask = new GlideRecord('x_153465_discovert_route_task_instance');
			if(grTask.get(requests.parent)){
				taskNumberAndName = grTask.number + ' - ' + grTask.task_name;
				var task_state = parseInt(grTask.getValue('state'));
				requests.setValue("u_status", 'Completed');
				switch (task_state) {
						// Task was cancelled
					case 7:
						requests.setValue("u_response_comments", gs.getMessage('Tasker - Open Request Comment for cancelled task'));
						break;
						// Task was completed
					case 3: case 4:
						requests.setValue("u_response_comments", gs.getMessage('Tasker - Open Request Comment for Closed tasks'));
						break;
				}
				// TO TEST, SET TESTING TO false ABOVE - this is in just for testing, it could be removed, but hurts nothing as long as testing is set to false above
				if(!testing)
					requests.update();

				grTask.setValue("active", false);
				// STRY0106180 - clear all request fields
				grTask.u_clarification_requested = false;
				grTask.extension_requested = false;
				grTask.reassignment_requested = false;
				grTask.extended_suspense_date = null;

				// TO TEST, SET TESTING TO false ABOVE - this is in just for testing, it could be removed, but hurts nothing as long as testing is set to false above
				if(!testing)
					grTask.update();
			}
			// TO TEST, SET TESTING TO false ABOVE - this is in just for testing, it could be removed, but hurts nothing as long as testing is set to false above
			if(!testing)
				numRequestsClosed +=1;
		} catch(e) {
			gs.error("Task Number - Tasker Number - Task Name:" + taskNumberAndName + 
					" - Error in 'Tasker 2.7-Close Requests on closed Task' - exception: " + e);
		}
	}

	if(numRequestsClosed == requestNotClosedCount){
		gs.info("Fix Script - Tasker 2.7-Close Requests on closed Task - Completed - all Requests on completed tasks have been marked coimplete.");
	} else {
		gs.info("Fix Script - Tasker 2.7-Close Requests on closed Task - Completed - Not all requests were marked complete. " + numRequestsClosed + " of " + requestNotClosedCount + " were closed. To see requests still remain open, run this query on the request table: u_status=In progress^parent.stateIN7,4,3");

	}

}
